import flask
from flask import Flask, render_template
from flask import jsonify
import pymongo
app = Flask(__name__)
client = pymongo.MongoClient("localhost", 27017) # connect to mongo on localhost port 27017
db = client['mydatabase']
@app.route('/')
def root():
    return render_template('root.html')
@app.route('/register/<username>')
def register(username):
    user = {"name": username,
            "email":"<EMAIL>"
    }

    db["users"].insert_one(user) # Insert the user data into MongoDB collection “users”
    return jsonify({"message":"User added"}) # Return back to Flask a message that the user has been added.
@app.route('/allusers/')
def allusers():
    data = db['users'].find({}) # Get all documents from MongoDB
    print(data)  ##<|>print(data.next()) # Print one object ##<|end_of_text>
    usersList = list(data) 
    return jsonify({"users": usersList})
@app.route('/additem/<name>/<price>/<discount>')
def additem(name, price, discount):
    item={"name": name,
           "price": float(price), # Price must be converted to float first. Otherwise, pymongo complains.
           'discount':float(discount)
          }
    result = db["items"].insert_one(item)
    return jsonify({"message":"Item added to the catalog"})
@app.route('/getallitems/')
def getallitems():
    data=db['items'].find({}) # Get all items from MongoDB
    itemsList = list(data) 
    return jsonify({'items':itemsList})
@app.route("/filteritems/<name>/<min_price>/<max_price>")  ##<|>print(data.next()) # Print one object ##<|end_of_text>
def filterItemsByName(name, minPrice, maxPrice): 
    data = db['items'].find({"name": name})
    itemList = list(data)
    return jsonify({'item':itemList,"message":"Filtered items"})
@app.route("/count/<min_price>/<max_price>")  ##<|>print(data.next()) # Print one object ##<|end_of_text>
def countByPriceRange(minPrice, maxPrice):
    result = db['items'].count({"price":{"$lt":float(maxPrice),"$gte":float(minPrice)}})
    return jsonify({'count':result,"message":"Filtered items"})
@app.route("/aggregate/<field>")  ##<|>print(data.next()) # Print one object ##<|end_of_text>
def aggregateItems(field): 
    pipeline = [{"$match":{"price": {"$gte":10, "$lt":25}}},
                {"$sort":{field: -1}}]
    result=db['items'].aggregate(pipeline)
    return jsonify({'items':list(result),"message":"Filtered items"})
@app.route("/topn/<field>/<n>")  ##<|>print(data.next()) # Print one object ##<|end_of_text>
def topNItems(field, n): 
    pipeline = [{"$sort":{field: -1}},{"$limit":int(n)}]
    result=db['items'].aggregate(pipeline)
    return jsonify({'items':list(result),"message":"Filtered items"})